let messages;
if (pdfBase64 && pdfBase64.length > 100) {
  messages = [{ role: 'user', content: [
    { type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: pdfBase64 } },
    { type: 'text', text: 'استخرج كل البيانات وأنشئ تقرير HTML بعنوان "' + reportTitle + '".
قواعد صارمة:
1. اقرأ عنوان كل قسم وجدول وشارت في الـ PDF أولاً قبل استخراج بياناته.
2. لا تخلط بيانات قسم مع قسم آخر — كل جدول وشارت له بياناته الخاصة.
3. جدول المواعيد (Appointments) غير جدول الفواتير (Invoices) غير جدول الملفات (Files).
4. لا تخترع بيانات. تأكد من استخراج كل KPI بدون نقصان — كل رقم ونسبة في Calls Summary و Appointments, Invoices & File Openings لازم يظهروا.
5. أضف توصيات وتحسينات بناءً على تحليل البيانات.
6. مهم: لازم التقرير يكون مكتمل — اكتب كل التوصيات كاملة ثم الـ footer "فريق تحليل البيانات- قسم التشغيل" ثم أغلق كل الـ tags.' }
  ]}];
} else {
  messages = [{ role: 'user', content: 'أنشئ تقرير HTML بعنوان "' + reportTitle + '": ' + (item.text_content ?? '') }];
}
const requestBody = {
  model: 'claude-sonnet-4-5',
  max_tokens: 16000,
  system: systemPrompt,
  messages: messages
};
return [{ json: { requestBody, report_title: reportTitle, pdf_base64: pdfBase64, system_prompt: systemPrompt } }];

