const item = $input.first().json;
const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-5',
  max_tokens: 300,
  messages: [{ role: 'user', content: 'راجع هذا التقرير وأجب بـ JSON فقط:\n{"complete": true, "missing": []}\n\n' + item.html_content.substring(0, 5000) }]
});
return [{ json: { requestBody, html_content: item.html_content, report_title: item.report_title, pdf_base64: item.pdf_base64, system_prompt: item.system_prompt } }];

const apiRes = $input.first().json;
const prepData = $('Prepare Review').first().json;
let reviewText = apiRes.content?.[0]?.text ?? '';
let result;
try {
  result = JSON.parse(reviewText.replace(/```json\n?/gi,'').replace(/```\n?/gi,'').trim());
} catch(e) {
  result = { complete: true, missing: [] };
}
return [{ json: {
  is_complete: result.complete,
  missing: result.missing ?? [],
  html_content: prepData.html_content,
  report_title: prepData.report_title,
  pdf_base64: prepData.pdf_base64,
  system_prompt: prepData.system_prompt
} }];

const item = $input.first().json;
const missing = item.missing.join('\n- ');
const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-5',
  max_tokens: 8000,
  system: item.system_prompt,
  messages: [{ role: 'user', content: [
    { type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: item.pdf_base64 } },
    { type: 'text', text: 'التقرير ناقص. النواقص:\n- ' + missing + '\n\nأعد إنشاء التقرير كامل مع إصلاح كل النواقص.' }
  ] }]
});
return [{ json: { requestBody, report_title: item.report_title } }];

